class LinkPreviewController extends Controller {    
public function getLink($url) {     
    $ch = curl_init();  
      
    curl_setopt( $ch, CURLOPT_URL, $url ); // set URL to open.       
    curl_setopt( $ch, CURLOPT_RETURNTRANSFER, 1);     // return web page content as a string (not parsed into a DOM structure).  
      
    $output = curl_exec($ch);     
        
